var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"KNIGHT_REPLACER_REGEN_NULL","text":{"KOREA":"......솔직히 말해서, 놀랍군.","JPN":"……正直に言って、驚いた。","ENG":"Honestly, I’m most impressed.","TWN":"……說實話，這真是令人驚訝。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_REGEN_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"KNIGHT_REPLACER_REGEN_NULL","text":{"KOREA":"이 정도의 군세를 끌고 왔는데도 겨우 호각세라니.","JPN":"これほどの軍勢を率いてきたのに、互角とは。","ENG":"I’ve brought a considerable force with me, yet you still manage to hold your ground.","TWN":"調來了這麼多兵力，結果好不容易才打成了平手。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"KNIGHT_REPLACER_REGEN_NULL","text":{"KOREA":"실로 기사의 싸움에 걸맞은 훌륭한 적이다. 경의를 표하지.","JPN":"まさしく騎士の戦いにふさわしい\\n立派な相手だ。敬意を表する。","ENG":"You are indeed a worthy enemy for a knight. Allow me to convey my respect.","TWN":"確實是值得與騎士一戰的敵人，值得敬佩。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......정신 나간 놈이군.","JPN":"……とんだ勘違い野郎だな。","ENG":"Okay, Don Quixote.","TWN":"……真是個瘋子。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"코드네임이 나이트라고 해서 정말 기사라도 된 기분인가?","JPN":"コードネームがナイトだからって、本当に騎士にでもなったつもりか？","ENG":"You think you're a real knight just because they gave you that code name?","TWN":"因為代碼名是Knight，所以也可以叫作騎士嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"KNIGHT_REPLACER_REGEN_NULL","text":{"KOREA":"하하, 도발하는 건가? 전사여.","JPN":"ハハ、それは挑発か？　戦士よ。","ENG":"Haha, are you trying to provoke me? Most worthy foe.","TWN":"哈哈，妳是在挑釁嗎？戰士。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_REGEN_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"KNIGHT_REPLACER_REGEN_NULL","text":{"KOREA":"허나 마음대로 비웃어도 좋다.","JPN":"しかし、好きなだけあざ笑うが良い。","ENG":"Ridicule me all you want.","TWN":"不過妳就盡情地嘲笑吧。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"KNIGHT_REPLACER_REGEN_NULL","text":{"KOREA":"난 지금 진실로 너희에게 감사하고 있으니까.","JPN":"私は今、本気で貴様らに感謝をしているからな。","ENG":"That won’t diminish the gratitude I have for you right now.","TWN":"因為我現在是真的很感謝你們。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"또 무슨 헛소리를......","JPN":"また戯言を……","ENG":"What kind of a crazy talk is this...","TWN":"這又是在說什麼……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"KNIGHT_REPLACER_REGEN_NULL","text":{"KOREA":"애당초 난 기습이나 암살 같은 임무에 걸맞지 않는다.","JPN":"そもそも私は、奇襲や暗殺のような任務には適していない。","ENG":"I was never designed for ambushes or assassinations in the first place.","TWN":"我本來就不適合偷襲或者暗殺的任務。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_REGEN_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"KNIGHT_REPLACER_REGEN_NULL","text":{"KOREA":"내 모체가 나에게 가르쳐 준 것은 단 하나.","JPN":"私の母体が私に教えてくれたことはただ一つ。","ENG":"There is only one thing my source has taught me.","TWN":"我的母體教我的事情只有一個。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"KNIGHT_REPLACER_REGEN_NULL","text":{"KOREA":"전투의 기쁨.","JPN":"戦うことの悦び。","ENG":"The ecstasy of battle.","TWN":"戰鬥的快感。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"KNIGHT_REPLACER_REGEN_NULL","text":{"KOREA":"난 지금 그 기쁨을 충분히 누리고 있다.","JPN":"私は今、その悦びを十分に味わっている。","ENG":"And I am indulging myself in such bliss right now.","TWN":"我現在就在盡情享受著這種快感。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하하, 말보다 주먹이라는 뜻인 것 같은데, 왠지 스승님이랑 잘 통할 것 같지 않나요?","JPN":"ハハ、「言葉よりも拳」と言いたいようですが、師匠と通じるところがありそうですね？","ENG":"Haha, sounds like a fancy way of saying “less talk, more fighting.” Don’t you think she’ll get along nicely with you, Master?","TWN":"哈哈，聽起來像是拳頭大於話語的意思，這不是和師父很合得來嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"KNIGHT_REPLACER_REGEN_NULL","text":{"KOREA":"허나 임무에 실패할 생각은 없다.","JPN":"だが、任務に失敗するつもりはない。","ENG":"Nevertheless, I have no plans to fail my mission.","TWN":"但是，我不會讓任務失敗的。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_REGEN_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"KNIGHT_REPLACER_REGEN_NULL","text":{"KOREA":"내키지는 않지만...... 도움을 요청할 시간이군.","JPN":"気が向かないが……支援を求める時だな。","ENG":"Although I am reluctant... The time has come to call for help.","TWN":"雖然不樂意……但希望您能幫助我。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......도움?","JPN":"……支援？","ENG":"Help?","TWN":"……幫助？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"KNIGHT_REPLACER_REGEN_NULL","text":{"KOREA":"여왕이시여. 부디 피와 강철과 충격은 제게 맡겨 주십시오.","JPN":"女王様、どうか血と鋼鉄と衝撃は私にお任せを。","ENG":"My Queen... Please leave the fire, iron, and blood to me.","TWN":"女王啊，請您把血、鋼鐵和衝擊交給我吧。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_REGEN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"KNIGHT_REPLACER_REGEN_NULL","text":{"KOREA":"여왕께는 왕의 명령을 부탁드립니다.","JPN":"女王には王の命令をお願いいたします。","ENG":"Instead, please carry out the King's bidding.","TWN":"這是王對您的命令。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"......알겠다. 그쪽은 내가 맡지.","JPN":"……わかった。そちらは私が受け持とう。","ENG":"Your plea has been heard. I will take care of that matter.","TWN":"……知道了。那邊我來負責。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_BOSS_QUEEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"엎드려......!","JPN":"……伏せろ！","ENG":"Get down!","TWN":"趴下……！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_BOSS_QUEEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"다친 덴 없으신가요, 스승님?","JPN":"怪我はありませんか、師匠？","ENG":"You alright, Master?","TWN":"師父，妳有受傷嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_BOSS_QUEEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그런데...... 방금 지나간 건 설마......","JPN":"ところで、今通り過ぎたのはまさか……","ENG":"By the way... That thing that just swept by...","TWN":"剛剛飛過去的東西……難道是……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_BOSS_QUEEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"어, 어디서 나타난 거야? 봤어?!","JPN":"どこから現れたんだ？　見たか！？","ENG":"W-where the heck did that just come from? Did you see that?","TWN":"從、從哪裡出現的啊？妳看到了嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_BOSS_QUEEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L45_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"아, 아니...... 전혀 안 보였는데......?!","JPN":"い、いや……全く見えなかったけど……！？","ENG":"N-no... Not at all...","TWN":"沒，沒有……完全沒看見……？！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_BOSS_QUEEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"그런데...... 저, 저거...... 혹시 <color=#ffd34c>그 사람</color>...... 아니야......?","JPN":"ところで……あ、あれって……\\nもしかして<color=#ffd34c>あの人</color>……じゃないかな……？","ENG":"By the way... I-is that... <color=#ffd34c>Her</color>? Is it who I think it is?","TWN":"但是……那、那個……該不會是<color=#ffd34c>那個人</color>嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_BOSS_QUEEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"뭐? 그 사람이라니, 갑자기 그 사람이 누군데......","JPN":"えっ？あの人って、誰のことを言ってる……","ENG":"Huh? Who are you talking about?","TWN":"什麼？妳說的那個人到底是誰……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_BOSS_QUEEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"야, 잠깐...... 저 얼굴...... 서, 설마?","JPN":"おい、ちょっと待て……あの顔……ま、まさか？","ENG":"Hey, hang on... That face... N-no way...","TWN":"啊，等等……那張臉……難、難道？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_BOSS_QUEEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"자, 잘못했어요! 감독관님!","JPN":"ご、ごめんなさい！　監督官！","ENG":"I-I’m sorry! Supervisor!","TWN":"我、我錯了！監察官大人！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_BOSS_QUEEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"이, 이 바보야! 지금 주저앉으면 어떡해?!","JPN":"バカ！　今座り込んでどうするんだ？","ENG":"You idiot! Don’t sit down right now!","TWN":"妳、妳這笨蛋！現在就腿軟是要怎樣？！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_BOSS_QUEEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"하, 하지만...... 하지만......!","JPN":"で、でも……でも……！","ENG":"B-but... But...","TWN":"但、但是……但是……！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_BOSS_QUEEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"대장?! 대장은 어디에 있지?!","JPN":"隊長？　隊長はどこにいる！？","ENG":"Cap... Where's the Cap?!","TWN":"隊長？！隊長在哪裡？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_BOSS_QUEEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"대장부터 찾아!","JPN":"まずは隊長を探すぞ！","ENG":"Find the Cap!","TWN":"先去找到隊長！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_BOSS_QUEEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_BOSS_QUEEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"야?! 멸치! 지, 지금 어딜 가는 거야?","JPN":"おい、イワシ！　どこ行くんだ？","ENG":"Hey! Weak Sauce! W-where are you going?","TWN":"喂？！小魚乾！妳、妳要去哪裡啊？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_BOSS_QUEEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"......야!","JPN":"……おい！","ENG":"Hey!","TWN":"……喂！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_BOSS_QUEEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};